#include <stdio.h>
int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        int n, m;
        scanf("%d %d", &n, &m);
        char grid[n][m];
        for (int i = 0; i < n; i++) {
            scanf(" %s", grid[i]);
        }
        int x, y, a, b;
        scanf("%d %d %d %d", &x, &y, &a, &b);
        int dp[n][m];
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < m; j++) {
                dp[i][j] = 0;
            }
        }
        dp[x-1][y-1] = 1;
        for (int i = x-1; i < n; i++) {
            for (int j = y-1; j < m; j++) {
                if (i < n-1 && grid[i+1][j] == '0') {
                    dp[i+1][j] += dp[i][j];
                }
                if (j < m-1 && grid[i][j+1] == '0') {
                    dp[i][j+1] += dp[i][j];
                }
            }
        }
        printf("%d\n", dp[a-1][b-1]);
    }
    return 0;
}

