def solve(n, m, grid, x, y, a, b):
    dp = [[0]*m for _ in range(n)]
    dp[x-1][y-1] = 1
    for i in range(x-1, n):
        for j in range(y-1, m):
            if i < n-1 and grid[i+1][j] == '0':
                dp[i+1][j] += dp[i][j]
            if j < m-1 and grid[i][j+1] == '0':
                dp[i][j+1] += dp[i][j]
    return dp[a-1][b-1]

